  2826ŌåÆmdb_txn_begin(MDB_env *env, MDB_txn *parent, unsigned int flags, MDB_txn **ret)
  2827ŌåÆ{
  2828ŌåÆ	MDB_txn *txn;
  2829ŌåÆ	MDB_ntxn *ntxn;
  2830ŌåÆ	int rc, size, tsize;
  2831ŌåÆ
  2832ŌåÆ	flags &= MDB_TXN_BEGIN_FLAGS;
  2833ŌåÆ	flags |= env->me_flags & MDB_WRITEMAP;
  2834ŌåÆ
  2835ŌåÆ	if (env->me_flags & MDB_RDONLY & ~flags) /* write txn in RDONLY env */
  2836ŌåÆ		return EACCES;
  2837ŌåÆ
  2838ŌåÆ	if (parent) {
  2839ŌåÆ		/* Nested transactions: Max 1 child, write txns only, no writemap */
  2840ŌåÆ		flags |= parent->mt_flags;
  2841ŌåÆ		if (flags & (MDB_RDONLY|MDB_WRITEMAP|MDB_TXN_BLOCKED)) {
  2842ŌåÆ			return (parent->mt_flags & MDB_TXN_RDONLY) ? EINVAL : MDB_BAD_TXN;
  2843ŌåÆ		}
  2844ŌåÆ		/* Child txns save MDB_pgstate and use own copy of cursors */
  2845ŌåÆ		size = env->me_maxdbs * (sizeof(MDB_db)+sizeof(MDB_cursor *)+1);
  2846ŌåÆ		size += tsize = sizeof(MDB_ntxn);
  2847ŌåÆ	} else if (flags & MDB_RDONLY) {
  2848ŌåÆ		size = env->me_maxdbs * (sizeof(MDB_db)+1);
  2849ŌåÆ		size += tsize = sizeof(MDB_txn);
  2850ŌåÆ	} else {
  2851ŌåÆ		/* Reuse preallocated write txn. However, do not touch it until
  2852ŌåÆ		 * mdb_txn_renew0() succeeds, since it currently may be active.
  2853ŌåÆ		 */
  2854ŌåÆ		txn = env->me_txn0;
  2855ŌåÆ		goto renew;
  2856ŌåÆ	}
  2857ŌåÆ	if ((txn = calloc(1, size)) == NULL) {
  2858ŌåÆ		DPRINTF(("calloc: %s", strerror(errno)));
  2859ŌåÆ		return ENOMEM;
  2860ŌåÆ	}
  2861ŌåÆ	txn->mt_dbxs = env->me_dbxs;	/* static */
  2862ŌåÆ	txn->mt_dbs = (MDB_db *) ((char *)txn + tsize);
  2863ŌåÆ	txn->mt_dbflags = (unsigned char *)txn + size - env->me_maxdbs;
  2864ŌåÆ	txn->mt_flags = flags;
  2865ŌåÆ	txn->mt_env = env;
  2866ŌåÆ
  2867ŌåÆ	if (parent) {
  2868ŌåÆ		unsigned int i;
  2869ŌåÆ		txn->mt_cursors = (MDB_cursor **)(txn->mt_dbs + env->me_maxdbs);
  2870ŌåÆ		txn->mt_dbiseqs = parent->mt_dbiseqs;
  2871ŌåÆ		txn->mt_u.dirty_list = malloc(sizeof(MDB_ID2)*MDB_IDL_UM_SIZE);
  2872ŌåÆ		if (!txn->mt_u.dirty_list ||
  2873ŌåÆ			!(txn->mt_free_pgs = mdb_midl_alloc(MDB_IDL_UM_MAX)))
  2874ŌåÆ		{
  2875ŌåÆ			free(txn->mt_u.dirty_list);
  2876ŌåÆ			free(txn);
  2877ŌåÆ			return ENOMEM;
  2878ŌåÆ		}
  2879ŌåÆ		txn->mt_txnid = parent->mt_txnid;
  2880ŌåÆ		txn->mt_dirty_room = parent->mt_dirty_room;
  2881ŌåÆ		txn->mt_u.dirty_list[0].mid = 0;
  2882ŌåÆ		txn->mt_spill_pgs = NULL;
  2883ŌåÆ		txn->mt_next_pgno = parent->mt_next_pgno;
  2884ŌåÆ		parent->mt_flags |= MDB_TXN_HAS_CHILD;
  2885ŌåÆ		parent->mt_child = txn;
  2886ŌåÆ		txn->mt_parent = parent;
  2887ŌåÆ		txn->mt_numdbs = parent->mt_numdbs;
  2888ŌåÆ		memcpy(txn->mt_dbs, parent->mt_dbs, txn->mt_numdbs * sizeof(MDB_db));
  2889ŌåÆ		/* Copy parent's mt_dbflags, but clear DB_NEW */
  2890ŌåÆ		for (i=0; i<txn->mt_numdbs; i++)
  2891ŌåÆ			txn->mt_dbflags[i] = parent->mt_dbflags[i] & ~DB_NEW;
  2892ŌåÆ		rc = 0;
  2893ŌåÆ		ntxn = (MDB_ntxn *)txn;
  2894ŌåÆ		ntxn->mnt_pgstate = env->me_pgstate; /* save parent me_pghead & co */
  2895ŌåÆ		if (env->me_pghead) {
  2896ŌåÆ			size = MDB_IDL_SIZEOF(env->me_pghead);
  2897ŌåÆ			env->me_pghead = mdb_midl_alloc(env->me_pghead[0]);
  2898ŌåÆ			if (env->me_pghead)
  2899ŌåÆ				memcpy(env->me_pghead, ntxn->mnt_pgstate.mf_pghead, size);
  2900ŌåÆ			else
  2901ŌåÆ				rc = ENOMEM;
  2902ŌåÆ		}
  2903ŌåÆ		if (!rc)
  2904ŌåÆ			rc = mdb_cursor_shadow(parent, txn);
  2905ŌåÆ		if (rc)
  2906ŌåÆ			mdb_txn_end(txn, MDB_END_FAIL_BEGINCHILD);
  2907ŌåÆ	} else { /* MDB_RDONLY */
  2908ŌåÆ		txn->mt_dbiseqs = env->me_dbiseqs;
  2909ŌåÆrenew:
  2910ŌåÆ		rc = mdb_txn_renew0(txn);
  2911ŌåÆ	}
  2912ŌåÆ	if (rc) {
  2913ŌåÆ		if (txn != env->me_txn0)
  2914ŌåÆ			free(txn);
  2915ŌåÆ	} else {
  2916ŌåÆ		txn->mt_flags |= flags;	/* could not change txn=me_txn0 earlier */
  2917ŌåÆ		*ret = txn;
  2918ŌåÆ		DPRINTF(("begin txn %"Z"u%c %p on mdbenv %p, root page %"Z"u",
  2919ŌåÆ			txn->mt_txnid, (flags & MDB_RDONLY) ? 'r' : 'w',
  2920ŌåÆ			(void *) txn, (void *) env, txn->mt_dbs[MAIN_DBI].md_root));
  2921ŌåÆ	}
  2922ŌåÆ
  2923ŌåÆ	return rc;
  2924ŌåÆ}
  2925ŌåÆ
  2926ŌåÆMDB_env *
  2927ŌåÆmdb_txn_env(MDB_txn *txn)
  2928ŌåÆ{
  2929ŌåÆ	if(!txn) return NULL;
  2930ŌåÆ	return txn->mt_env;
  2931ŌåÆ}
