  3073ŌåÆmdb_freelist_save(MDB_txn *txn)
  3074ŌåÆ{
  3075ŌåÆ	/* env->me_pghead[] can grow and shrink during this call.
  3076ŌåÆ	 * env->me_pglast and txn->mt_free_pgs[] can only grow.
  3077ŌåÆ	 * Page numbers cannot disappear from txn->mt_free_pgs[].
  3078ŌåÆ	 */
  3079ŌåÆ	MDB_cursor mc;
  3080ŌåÆ	MDB_env	*env = txn->mt_env;
  3081ŌåÆ	int rc, maxfree_1pg = env->me_maxfree_1pg, more = 1;
  3082ŌåÆ	txnid_t	pglast = 0, head_id = 0;
  3083ŌåÆ	pgno_t	freecnt = 0, *free_pgs, *mop;
  3084ŌåÆ	ssize_t	head_room = 0, total_room = 0, mop_len, clean_limit;
  3085ŌåÆ
  3086ŌåÆ	mdb_cursor_init(&mc, txn, FREE_DBI, NULL);
  3087ŌåÆ
  3088ŌåÆ	if (env->me_pghead) {
  3089ŌåÆ		/* Make sure first page of freeDB is touched and on freelist */
  3090ŌåÆ		rc = mdb_page_search(&mc, NULL, MDB_PS_FIRST|MDB_PS_MODIFY);
  3091ŌåÆ		if (rc && rc != MDB_NOTFOUND)
  3092ŌåÆ			return rc;
  3093ŌåÆ	}
  3094ŌåÆ
  3095ŌåÆ	if (!env->me_pghead && txn->mt_loose_pgs) {
  3096ŌåÆ		/* Put loose page numbers in mt_free_pgs, since
  3097ŌåÆ		 * we may be unable to return them to me_pghead.
  3098ŌåÆ		 */
  3099ŌåÆ		MDB_page *mp = txn->mt_loose_pgs;
  3100ŌåÆ		MDB_ID2 *dl = txn->mt_u.dirty_list;
  3101ŌåÆ		unsigned x;
  3102ŌåÆ		if ((rc = mdb_midl_need(&txn->mt_free_pgs, txn->mt_loose_count)) != 0)
  3103ŌåÆ			return rc;
