  3114ŌåÆ				mdb_tassert(txn, dl[x].mid == mp->mp_pgno);
  3115ŌåÆ				mdb_dpage_free(env, mp);
  3116ŌåÆ			}
  3117ŌåÆ			dl[x].mptr = NULL;
  3118ŌåÆ		}
