  3120ŌåÆ			/* squash freed slots out of the dirty list */
  3121ŌåÆ			unsigned y;
  3122ŌåÆ			for (y=1; dl[y].mptr && y <= dl[0].mid; y++);
  3123ŌåÆ			if (y <= dl[0].mid) {
  3124ŌåÆ				for(x=y, y++;;) {
  3125ŌåÆ					while (!dl[y].mptr && y <= dl[0].mid) y++;
