  3128ŌåÆ				}
  3129ŌåÆ				dl[0].mid = x-1;
  3130ŌåÆ			} else {
  3131ŌåÆ				/* all slots freed */
  3132ŌåÆ				dl[0].mid = 0;
  3133ŌåÆ			}
  3134ŌåÆ		}
