  3189ŌåÆ				unsigned int i = free_pgs[0];
  3190ŌåÆ				DPRINTF(("IDL write txn %"Z"u root %"Z"u num %u",
  3191ŌåÆ					txn->mt_txnid, txn->mt_dbs[FREE_DBI].md_root, i));
  3192ŌåÆ				for (; i; i--)
  3193ŌåÆ					DPRINTF(("IDL %"Z"u", free_pgs[i]));
  3194ŌåÆ			}
  3195ŌåÆ#endif
