  3197ŌåÆ		}
  3198ŌåÆ
  3199ŌåÆ		mop = env->me_pghead;
  3200ŌåÆ		mop_len = (mop ? mop[0] : 0) + txn->mt_loose_count;
  3201ŌåÆ
  3202ŌåÆ		/* Reserve records for me_pghead[]. Split it if multi-page,
