  3226ŌåÆ		key.mv_data = &head_id;
  3227ŌåÆ		data.mv_size = (head_room + 1) * sizeof(pgno_t);
  3228ŌåÆ		rc = mdb_cursor_put(&mc, &key, &data, MDB_RESERVE);
  3229ŌåÆ		if (rc)
